Bind the AudioSource reverbZoneMix property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceReverbZoneMixBinder _reverbZoneMix;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _reverbZoneMix;
    }


Bind the AudioSource reverbZoneMix property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceReverbZoneMixBinder ReverbZoneMix =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _reverbZoneMix;
    }

Switch the AudioSource reverbZoneMix between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceReverbZoneMixSwitcherBinder _isHighReverbMix;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighReverbMix;
    }


Switch the AudioSource reverbZoneMix between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private float _highReverbMix;
        
        [SerializeField] 
        private float _lowReverbMix;
        
        private AudioSourceReverbZoneMixSwitcherBinder IsHighReverbMix => new(
            _audioSource, _highReverbMix, _lowReverbMix);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighReverbMix;
    }
